from flask import Flask, request, jsonify
from pymongo import MongoClient
from bson import ObjectId
from bson.errors import InvalidId
from datetime import datetime
import os

app = Flask(__name__)

MONGO_URI = os.getenv("MONGO_URI", "mongodb://localhost:27017")
DB_NAME = os.getenv("MONGO_DB_NAME", "cms")
client = MongoClient(MONGO_URI)
db = client[DB_NAME]

users_collection = db["users"]
documents_collection = db["documents"]


def serialize_value(value):
    if isinstance(value, ObjectId):
        return str(value)
    if isinstance(value, datetime):
        return value.isoformat()
    if isinstance(value, list):
        return [serialize_value(v) for v in value]
    if isinstance(value, dict):
        return {k: serialize_value(v) for k, v in value.items()}
    return value


def serialize_document(doc):
    if not doc:
        return None
    return serialize_value(doc)


def parse_object_id(value):
    try:
        return ObjectId(value)
    except (InvalidId, TypeError):
        return None


@app.route("/health", methods=["GET"])
def health():
    try:
        client.admin.command("ping")
        return jsonify({"status": "ok", "mongodb": "connected"})
    except Exception as e:
        return jsonify({"status": "error", "message": str(e)}), 500


@app.route("/users", methods=["POST"])
def create_user_profile():
    data = request.get_json(silent=True) or {}

    required_fields = ["username", "email"]
    missing = [field for field in required_fields if not data.get(field)]
    if missing:
        return jsonify({"error": f"Missing required fields: {', '.join(missing)}"}), 400

    user = {
        "username": data["username"],
        "email": data["email"],
        "full_name": data.get("full_name"),
        "bio": data.get("bio", ""),
        "roles": data.get("roles", ["author"]),
        "preferences": data.get("preferences", {}),
        "created_at": datetime.utcnow(),
        "updated_at": datetime.utcnow(),
    }

    result = users_collection.insert_one(user)
    user["_id"] = result.inserted_id
    return jsonify(serialize_document(user)), 201


@app.route("/users", methods=["GET"])
def list_user_profiles():
    query = {}
    username = request.args.get("username")
    email = request.args.get("email")
    role = request.args.get("role")

    if username:
        query["username"] = {"$regex": username, "$options": "i"}
    if email:
        query["email"] = {"$regex": email, "$options": "i"}
    if role:
        query["roles"] = role

    users = list(users_collection.find(query).sort("created_at", -1))
    return jsonify([serialize_document(user) for user in users])


@app.route("/users/<user_id>", methods=["GET"])
def get_user_profile(user_id):
    oid = parse_object_id(user_id)
    if not oid:
        return jsonify({"error": "Invalid user id"}), 400

    user = users_collection.find_one({"_id": oid})
    if not user:
        return jsonify({"error": "User not found"}), 404

    return jsonify(serialize_document(user))


@app.route("/users/<user_id>", methods=["PUT"])
def update_user_profile(user_id):
    oid = parse_object_id(user_id)
    if not oid:
        return jsonify({"error": "Invalid user id"}), 400

    data = request.get_json(silent=True) or {}
    allowed_fields = {"username", "email", "full_name", "bio", "roles", "preferences"}
    update_fields = {k: v for k, v in data.items() if k in allowed_fields}
    if not update_fields:
        return jsonify({"error": "No valid fields provided for update"}), 400

    update_fields["updated_at"] = datetime.utcnow()

    result = users_collection.update_one({"_id": oid}, {"$set": update_fields})
    if result.matched_count == 0:
        return jsonify({"error": "User not found"}), 404

    user = users_collection.find_one({"_id": oid})
    return jsonify(serialize_document(user))


@app.route("/users/<user_id>", methods=["DELETE"])
def delete_user_profile(user_id):
    oid = parse_object_id(user_id)
    if not oid:
        return jsonify({"error": "Invalid user id"}), 400

    result = users_collection.delete_one({"_id": oid})
    if result.deleted_count == 0:
        return jsonify({"error": "User not found"}), 404

    return jsonify({"message": "User deleted"})


@app.route("/documents", methods=["POST"])
def create_document():
    data = request.get_json(silent=True) or {}

    required_fields = ["title", "content", "author_id"]
    missing = [field for field in required_fields if not data.get(field)]
    if missing:
        return jsonify({"error": f"Missing required fields: {', '.join(missing)}"}), 400

    author_oid = parse_object_id(data["author_id"])
    if not author_oid:
        return jsonify({"error": "Invalid author_id"}), 400

    author = users_collection.find_one({"_id": author_oid})
    if not author:
        return jsonify({"error": "Author not found"}), 404

    document = {
        "title": data["title"],
        "content": data["content"],
        "author_id": author_oid,
        "status": data.get("status", "draft"),
        "tags": data.get("tags", []),
        "category": data.get("category"),
        "metadata": data.get("metadata", {}),
        "published_at": data.get("published_at"),
        "created_at": datetime.utcnow(),
        "updated_at": datetime.utcnow(),
    }

    result = documents_collection.insert_one(document)
    document["_id"] = result.inserted_id
    return jsonify(serialize_document(document)), 201


@app.route("/documents", methods=["GET"])
def query_documents():
    query = {}
    title = request.args.get("title")
    status = request.args.get("status")
    category = request.args.get("category")
    tag = request.args.get("tag")
    author_id = request.args.get("author_id")

    if title:
        query["title"] = {"$regex": title, "$options": "i"}
    if status:
        query["status"] = status
    if category:
        query["category"] = category
    if tag:
        query["tags"] = tag
    if author_id:
        author_oid = parse_object_id(author_id)
        if not author_oid:
            return jsonify({"error": "Invalid author_id"}), 400
        query["author_id"] = author_oid

    limit = min(int(request.args.get("limit", 20)), 100)
    skip = max(int(request.args.get("skip", 0)), 0)

    documents = list(
        documents_collection.find(query).sort("created_at", -1).skip(skip).limit(limit)
    )
    return jsonify([serialize_document(doc) for doc in documents])


