    pipeline = [
        {"$group": {"_id": "$author_id", "document_count": {"$sum": 1}}},
        {"$sort": {"document_count": -1}},
        {"$limit": limit},
        {
            "$lookup": {
                "from": "users",
                "localField": "_id",
                "foreignField": "_id",
                "as": "author",
            }
        },
        {"$unwind": {"path": "$author", "preserveNullAndEmptyArrays": True}},
        {
            "$project": {
                "_id": 0,
                "author_id": "$_id",
                "document_count": 1,
                "username": "$author.username",
                "email": "$author.email",
                "full_name": "$author.full_name",
            }
        },
    ]
